def clicks_per_user(ev):
    r = {}; i = 0; n = len(ev)
    while i < n:
        e = ev[i]
        if e[1] == 'click':
            k = e[0]; f = 0
            if k in r: f = r[k]
            r[k] = f + 1
        i += 1
    return r

from collections import Counter

def clicks_per_user(events):
    return dict(Counter(
        user for user, action in events
        if action == 'click'
    ))

