from collections import Counter
assert clicks_per_user(events) == {"alice": 3, "bob": 2, "carol": 1}
assert clicks_per_user([]) == {}
assert clicks_per_user([("x", "view"), ("x", "view")]) == {}
assert clicks_per_user([("z", "click")]) == {"z": 1}
# users with zero clicks must not appear
assert "carol" not in clicks_per_user([("carol", "view"), ("dan", "click")])
# identical output to the original tangle across varied inputs
def _original(ev):
    r = {}
    for u, a in ev:
        if a == "click":
            r[u] = r.get(u, 0) + 1
    return r
for sample in [events, [], [("p", "click"), ("q", "click"), ("p", "click"), ("q", "view")], [("a", "view")]]:
    assert clicks_per_user(sample) == _original(sample)
